import json, urllib.request
metrics={'queries':0,'tokens':0,'errors':0}
for q in ['mitigate sqli','what is xss','patch log4j']:
    data=json.dumps({'model':'gemma3:4b','prompt':'Answer briefly: '+q,'stream':False,'options':{'num_predict':12}}).encode()
    req=urllib.request.Request('http://211.170.162.139:10934/api/generate',data=data,headers={'Content-Type':'application/json'})
    try:
        r=json.loads(urllib.request.urlopen(req).read())
        metrics['queries']+=1
        metrics['tokens']+=r.get('eval_count',0)
    except Exception:
        metrics['errors']+=1
print('=== RAG Monitoring ===')
for k,v in metrics.items():
    print(f' {k}: {v}')
